// mockUnaryInvoker simulates the actual network call to the etcd endpoint.
// It attempts to perform work but respects the context cancellation.
func mockUnaryInvoker(ctx context.Context) error {
	// Simulate a network operation that takes longer (50ms) than the context deadline allows
	select {
	case <-time.After(50 * time.Millisecond):
		return nil // Success
	case <-ctx.Done():
		// When context expires, gRPC clients typically return a specific error wrapping the context error
		if ctx.Err() == context.DeadlineExceeded {
			return ErrRPCTimeout
		}
		return ctx.Err()
	}
}

// retryInterceptor simulates the logic in clientv3/retry_interceptor.go
// It attempts to invoke the handler and manages retries (simplified here to just the failure case).
func retryInterceptor(ctx context.Context, invoker func(context.Context) error) error {
	// Attempt to invoke. In the real error scenario, the context deadline is hit
	// either before or during this call.
	err := invoker(ctx)

// If the error indicates a deadline exceeded, the retry logic stops and returns the error.
	if errors.Is(err, ErrRPCTimeout) {
		// Log logic would happen here: "retrying of unary invoker failed"
		return err
	}
	return err
}

func TestEtcdContextDeadlineExceeded(t *testing.T) {
	// 1. Setup: Create a context with a very short deadline (1ms)
	// This simulates the condition where the request cannot complete within the allocated time
	// due to system load or network latency.
	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Millisecond)
	defer cancel()

// 2. Execution: Attempt to call the invoker through the interceptor
	err := retryInterceptor(ctx, mockUnaryInvoker)

// 3. Assertion: Verify the error matches the stack trace error
	if err == nil {
		t.Fatal("Expected error due to context deadline, got nil")
	}

expectedError := "rpc error: code = DeadlineExceeded desc = context deadline exceeded"
	if err.Error() != expectedError {
		t.Errorf("Expected error message to be '%s', got '%s'", expectedError, err.Error())
	}
}

